import React from 'react'
import './Footer.css';

import heart from '../../Assets/heart.gif';
import mail from '../../Assets/gmail.png';
import insta from '../../Assets/instagram.png';
import linked from '../../Assets/linkedin.png';
import phone from '../../Assets/smartphone.png';
export const Footer = () => {
  return (
    <div className='footholder'>
        <div className='foothold'>
            <div className='footsubhold footsubhold1'>
                <div><span className='footheading'>Sachine Tools </span></div>
                <div><span className='foottext'>To manufacture the offered products as per the set industry norms, we have developed a well-equipped and designed infrastructure facility at our premises. Our professionals are selected through industry approved selection procedures.</span></div>

            </div>
            

            <div className='footsubhold footsubhold3'>
                <div><span className='footheading'>CONTACT US</span></div>
                <div><span className='foottext'>S. NO. 38/1, KHEDEKAR INDUSTRIAL ESTATE, BEHIND PARI CO., NARHEGAON, <br></br>PUNE -411041</span></div>
                <div className='mailHold2'><img src={phone} className='iconImg'></img><p className='num'>+919850089067|+919850089065</p></div>
                <div className='mailHold'><img src={mail} className='iconImg'></img><span className='num'>sachintoolsengg@gmail.com|sachintoolsengg@yahoo.co.in</span></div>
            </div>
        </div>
        <hr className='footline'></hr>

        <div className='footiconHold'>
            <a target="_blank" href='https://www.instagram.com/saihccpune/'><img src={insta} className='iconImg'></img></a>
            <a target="_blank" href='https://www.linkedin.com/in/sai-hcc-61105527b/'><img src={linked} className='iconImg'></img></a>
        </div>

        <div className='copy'>Copyright &copy; 2023 Sachin tools  | Made with <img src={heart} className='footimage'></img> by CORTICA WEB SOLUTIONS PVT LTD</div>
    </div >

  )
}
